def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    n = edge_distance.shape[0]
    updated_edge_distance = edge_distance.copy()
    median_use = np.median(edge_n_used)

    # Distinct penalty and reward factors
    high_penalty_factor = 1.3  # Increased penalty for highly used edges
    low_penalty_factor = 1.1  # Lower penalty for moderately used edges
    high_reward_factor = 0.8  # Increased reward for least used edges
    low_reward_factor = 0.9   # Lower reward for moderately less used edges

    percentile_50 = np.percentile(edge_n_used, 50)
    percentile_90 = np.percentile(edge_n_used, 90)
    percentile_10 = np.percentile(edge_n_used, 10)

    # Apply penalties and rewards depending on edge usage relative to the median
    for tour in local_opt_tours:
        for i in range(len(tour) - 1):
            from_node, to_node = tour[i], tour[i+1]
            edge_usage = edge_n_used[from_node, to_node]

            if edge_usage > median_use:
                if edge_usage > percentile_90:
                    penalty_factor = high_penalty_factor
                else:
                    penalty_factor = low_penalty_factor
                updated_edge_distance[from_node, to_node] *= penalty_factor
                updated_edge_distance[to_node, from_node] *= penalty_factor

    for i in range(n):
        for j in range(i+1, n):
            edge_usage = edge_n_used[i, j]
            if edge_usage < median_use:
                if edge_usage < percentile_10:
                    reward_factor = high_reward_factor
                else:
                    reward_factor = low_reward_factor
                updated_edge_distance[i, j] *= reward_factor
                updated_edge_distance[j, i] *= reward_factor

    return updated_edge_distance

