def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = np.copy(edge_distance)
    max_usage = np.max(edge_n_used)

    for i in range(edge_distance.shape[0]):
        for j in range(edge_distance.shape[1]):
            if edge_n_used[i][j] == 0:
                continue
            relative_usage = 1 - (edge_n_used[i][j] / max_usage)
            updated_edge_distance[i][j] *= np.exp(-2 * relative_usage)

    return updated_edge_distance

import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = np.where(edge_n_used > 0, edge_distance * 1.1, edge_distance * 0.9)  # Globally modulates based on usage
    dynamic_penalty_factor = 1.1  # Base penalty value
    reward_factor = 0.9  # Rewarding less used edges

    n = edge_distance.shape[0]

    # Apply dynamic penalty for very frequently used edges in local optimal tours
    for tour in local_opt_tours:
        for i in range(len(tour) - 1):
            edge_from = tour[i]
            edge_to = tour[i + 1]
            # Enhance penalty according to their presence in optimal tours
            if edge_n_used[edge_from, edge_to] > np.percentile(edge_n_used, 75):
                updated_edge_distance[edge_from, edge_to] *= dynamic_penalty_factor ** (edge_n_used[edge_from, edge_to] / np.max(edge_n_used))
                updated_edge_distance[edge_to, edge_from] *= dynamic_penalty_factor ** (edge_n_used[edge_to, edge_from] / np.max(edge_n_used))

    # Applying a general reward to less used edges not addressed earlier
    for i in range(n):
        for j in range(i+1, n):
            if edge_n_used[i, j] < np.percentile(edge_n_used, 25):
                updated_edge_distance[i, j] *= reward_factor
                updated_edge_distance[j, i] *= reward_factor

    return updated_edge_distance
